// Combine and analyze content gaps
const items = $input.all();
const opportunityQueries = items.filter(i => i.json.query).map(i => i.json);
const unmatchedKeywords = items.filter(i => i.json.keyword).map(i => i.json);

const gaps = [];

// Add opportunity queries as gaps
opportunityQueries.forEach(q => {
  gaps.push({
    gap_type: 'ranking_opportunity',
    topic: q.query,
    source: 'gsc_search_performance',
    priority: 'high',
    reason: 'High impressions but low CTR and poor ranking'
  });
});

// Add unmatched keywords as gaps
unmatchedKeywords.forEach(kw => {
  gaps.push({
    gap_type: 'missing_content',
    topic: kw.keyword,
    source: 'tracked_keywords',
    search_volume: kw.search_volume,
    difficulty: kw.keyword_difficulty,
    priority: kw.search_volume > 1000 ? 'high' : kw.search_volume > 500 ? 'medium' : 'low',
    reason: 'Tracked keyword with no matching content'
  });
});

return [{ 
  json: { 
    gaps,
    total_gaps: gaps.length,
    ranking_opportunities: opportunityQueries.length,
    missing_content: unmatchedKeywords.length,
    analyzed_at: new Date().toISOString()
  } 
}];

